// ✅ SECURE: Use environment variables safely
require('dotenv').config(); // Load from .env (never committed)

const validateEnv = () => {
  const required = ['JWT_SECRET', 'DATABASE_URL', 'NODE_ENV'];
  const missing = required.filter(key => !process.env[key]);

  if (missing.length > 0) {
