```

```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.'
});

app.use(limiter);

// Stricter limit for sensitive endpoints
const strictLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5
});

app.post('/login', strictLimiter, (req, res) => {
  // Handle login
});
```

---

### 7. 🟡 **No Error Handling Middleware** (MEDIUM)
**Issue:** Unhandled errors could expose sensitive information or crash the server

**Remediation:**
```javascript
// Add this AFTER all other middleware
app.use((err, req, res, next) => {
  console.error(err.stack);

  // Don't expose error details in production
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal Server Error' 
    : err.message;

  res.status(err.status || 500).json({ 
    error: message,
    requestId: req.id // For debugging
  });
});
```

